    def _sort_palette(self, sort_palette):
        """
        Re-orders this image's palette, remapping pixel indices to match, and
        returns the resulting image. Used by :py:meth:`~PIL.Image.Image.quantize`.
        """
        from . import ImagePalette

        mode = self.palette.mode
        band_count = len(mode)
        raw_palette = self.palette.palette
        num_colors = len(raw_palette) // band_count
        palette_colors = [
            raw_palette[i * band_count : (i + 1) * band_count]
            for i in range(num_colors)
        ]

        if sort_palette == "brightness":

            def sort_key(color):
                if len(color) >= 3:
                    r, g, b = color[0], color[1], color[2]
                    return 0.299 * r + 0.587 * g + 0.114 * b
                return color[0]

        elif sort_palette == "rgb":

            def sort_key(color):
                return tuple(color)

        else:
            raise ValueError("sort_palette must be 'brightness', 'rgb' or None")

        order = sorted(range(num_colors), key=lambda i: sort_key(palette_colors[i]))

        new_palette = bytearray()
        mapping = [0] * num_colors
        for new_index, old_index in enumerate(order):
            new_palette.extend(palette_colors[old_index])
            mapping[old_index] = new_index

        im = self._new(self.im.point(mapping, None))
        im.palette = ImagePalette.ImagePalette(mode, bytes(new_palette))
        return im"}

